const require_validation = require('./validation.cjs');
const require_findAyahIdBySurah = require('./findAyahIdBySurah.cjs');
const require_findSurahAyahByAyahId = require('./findSurahAyahByAyahId.cjs');

//#region src/prevAyah.ts
/**
* Get the previous ayah for the given surah and ayah number.
* @param surah - The surah number.
* @param ayah - The ayah number within the surah.
* @param data - The Lists object containing SurahList.
* @returns The surah and ayah number of the previous ayah.
*/
function prevAyah(surah, ayah, data) {
	require_validation.checkValidSurah(surah, data.meta);
	const ayahId = require_findAyahIdBySurah.findAyahIdBySurah(surah, ayah, data);
	return require_findSurahAyahByAyahId.findSurahAyahByAyahId(ayahId == 1 ? data.meta.numAyahs : ayahId - 1, data);
}

//#endregion
exports.prevAyah = prevAyah;